<template>
    <section>
            <loader :is-visible="isLoading"></loader>
            <tg-list :IsShowAction="IsShowAction" :showCheckBox="isShowCheckBox" ModuleName="Billing" :listType="['List']"
                :HeaderButtons="listheaderbuttons" :HeaderText="billingRule"
                :RenderRowActionMethod="renderActions" v-on:ActionButtonClick="actionButtonClick"
                SubModuleCode="Billing" IdentityColumn="limitId" :ListData="LimitData" :HeaderData="Headers"
                :callbackfunction="FetchData" v-on:HeaderButtonClick="commonHeaderButtonClick"
                :TotalRecords="TotalRecords" :ListDataCallBackFunction="FetchData" :LegendArray="[]" :SortExp="sortExp"
                :SortBy="SortBy" :NorecordfoundText="$t('NoRecordfound')" v-on:PagerButtonClick="pagerMethod"
                v-on:SortdataButtonClick="sortdata" :routeInfo="$router">
                <template v-slot:slotdata="{ data }">
                    <template v-if="data.column.COLUMN_NAME == 'dayLimit'">
                        <span> {{ data.row.dayLimit !== null && data.row.dayLimit !== '' 
                                ? data.row.dayLimit + ' day(s)' 
                                : '-' }}
                        </span>
                    </template>
                      <template v-if="data.column.COLUMN_NAME == 'MoveDisplayOrder'"> 
                   <div class="text-center single-action">
                        <a href="javascript:void(0)" v-if="!isFirstItem(data.row)" class="UpDisplayOrder" @click="UpOrder(data.row)">
                        <em class="fa fa-arrow-circle-up text-primary mx-1 action-icon UpDisplayOrder"></em>
                    </a>
                        <a href="javascript:void(0)" v-if="!isLastItem(data.row)" class="DownDisplayOrder" @click="DownOrder(data.row)">
                        <em class="fa fa-arrow-circle-down text-primary mx-1 action-icon DownDisplayOrder"></em>
                    </a>
                    </div> 
                </template> 
                </template>
            </tg-list>
        <AddLimit v-if="isAddLimit" :callbackfunction="FetchData" :refCode="refCode" @CloseLimit="CloseLimit"
            :configurationId="this.configurationId" :EditLimitData="EditLimitData" :clientId="clientId">
        </AddLimit>
    </section>
</template>
<script>

import DataService from '../../../services/DataService';
import AddLimit from './AddLimit.vue'
export default {
    components: { AddLimit },
    props: {
        configurationId: {
            type: String,
            default: null
        },
        mode: {
            type: String,
            default: 'Edit'
        },
        isBillingType :{
            type: Boolean,
            required: false
        },
        clientId: {
            type: Number,
            default: false
        },
        billingRule:{
            type : String,
            required : false
        }
    },
    data() {
        return {
            isLimitEditMode: false, 
            selectedLimitItem: null,
            EditLimitData: [],
            isLoading: false,
            refCode: '',
            isAddLimit: false,
            noRecord: true,
            LimitData: [],
            TotalRecords: 0,
            ConfigId: 0,
            LimitId: 0,
            Sort_By: '',
            Sort_Exp: '',
            PageSize: 10,
            PageNumber: 1,
            isShowCheckBox:true,
            IsShowAction: false,
            IsWrongDisplayOrder:false,
            Headers: [
                {
                    COLUMN_NAME: "clientLimitName",
                    DATA_TYPE: "text",
                    SORTABLE: false,
                    VISIBLE: true,
                    DISPLAY_NAME: this.$t('LimitFor'),
                    DISPLAY_ORDER: 1,
                },
                {
                    COLUMN_NAME: "workCode",
                    DATA_TYPE: "text",
                    SORTABLE: false,
                    VISIBLE: true,
                    DISPLAY_NAME: this.$t('RateCode'),
                    DISPLAY_ORDER: 2,
                },
                {
                    COLUMN_NAME: "limitValue",
                    DATA_TYPE: "text",
                    SORTABLE: false,
                    VISIBLE: true,
                    DISPLAY_NAME: this.$t('LimitValue'),
                    DISPLAY_ORDER: 3,
                },
                {
                    COLUMN_NAME: "dayLimit",
                    DATA_TYPE: "text",
                    SORTABLE: false,
                    VISIBLE: true,
                    DISPLAY_NAME: this.$t('DayLimit'),
                    DISPLAY_ORDER: 4,
                    settings: {
                        isInSlot: true,
                    }
                },
                {
                    COLUMN_NAME: "alternateWorkCode",
                    DATA_TYPE: "text",
                    SORTABLE: false,
                    VISIBLE: true,
                    DISPLAY_NAME: this.$t('AlternateWorkCode'),
                    DISPLAY_ORDER: 5,
                },

                {
                    COLUMN_NAME: "displayOrder",
                    DATA_TYPE: "number",
                    SORTABLE: false,
                    VISIBLE: true,
                    DISPLAY_NAME: this.$t('DisplayOrder'),
                    DISPLAY_ORDER: 6,
                },
                {
                    COLUMN_NAME: "MoveDisplayOrder",
                    DATA_TYPE: "number",
                    SORTABLE: false,
                    VISIBLE: true,
                    DISPLAY_NAME: this.$t('MoveDisplayOrder'),
                    DISPLAY_ORDER: 6,
                    settings: {
                        isInSlot: true,
                    }
                }

            ],
            listheaderbuttons:
                [
                    {
                        title: 'Add Limit',
                        iconClass: 'fa fa-plus',
                        callbackfunction: 'Add',
                        additionalClass: '',
                        isdisabled: false,
                        isvisible: true,
                        checkPrivilege: false,
                    },
                    {
                        title: 'Delete',
                        iconClass: 'fa fa-trash',
                        callbackfunction: 'Delete',
                        additionalClass: '',
                        isdisabled: true,
                        isvisible: true,
                        checkPrivilege: false,
                        isEnabledOnSelectedRow: true
                    },
                        {
                        title: 'Edit',
                        iconClass: 'fa fa-pencil',
                        callbackfunction: 'Edit',
                        additionalClass: '',
                        isdisabled: false,
                        isvisible: true,
                        checkPrivilege: false,
                        isEnabledOnSelectedRow: true
                    },
                          {
                        title: 'Save',
                        iconClass: 'fa fa-save',
                        callbackfunction: 'Save',
                        additionalClass: '',
                        isdisabled: false,
                        isvisible: true,
                        checkPrivilege: false,
                        isEnabledOnSelectedRow: true
                    },
                    {
                        title: 'Back',
                        iconClass: 'fa fa-angle-double-left',
                        callbackfunction: 'BackToList',
                        additionalClass: '',
                        isdisabled: false,
                        isvisible: true,
                        checkPrivilege: false
                    }
                ],
            listActions: [
                {
                    title: 'Edit',
                    callbackfunction: 'EditRecord',
                    icon: 'fa fa-pencil text-success action-icon',
                    additionalSpan: '',
                    
                }
            ],
        }
    },
		async created() {
        var ths = this;
        await ths.FetchData();
        ths.IsShowAction= ths.mode =='View'? false: true;
        if(ths.mode == 'View'){
            // ths.listheaderbuttons[1].isvisible=true;
            ths.listheaderbuttons[2].isvisible=true;
            ths.listheaderbuttons[3].isvisible=false;
        }else{
            // ths.listheaderbuttons[1].isvisible=false;
            ths.listheaderbuttons[2].isvisible=false;
            ths.listheaderbuttons[3].isvisible=true;
        }
    },
    methods: {
         saveServiceRules: function (type) {
            debugger
            let ths = this;
            var obj = {
                //planServiceId: item.plan_service_id,
                configurationId: this.configurationId,
                rules: []
            };
            this.jsonToSaveRules = [];
            this.rules.forEach(function (rule, index) {
                ths.makeJsonForSave(rule);
            });
            obj.rules = ths.jsonToSaveRules;
            debugger;
            // if(this.isBillingType)
            // {
            //     nodeRuleData.forEach(item => {
            //         if (typeof item.DISPLAY_NODE_NAME === "string" && item.DISPLAY_NODE_NAME.toLowerCase() !== "global") 
            //             {
            //                 let obj = {
            //                             ConnfigurationId: item.CONFIGURATION_ID,
            //                             DisplayOrder: item.DISPLAY_ORDER,
            //                             NodeName: item.DISPLAY_NODE_NAME,
            //                             ServiceId: item.SERVICE_ID,
            //                             ClientServiceMappingId: 0,
            //                             OriginalConfigId: ths.oldConfigId,
            //                             ClientId: item.CLIENT_ID,
            //                             Type: "TM"
            //                 };
            //             ths.nodeList.push(obj);
            //         }
            //     });
            //     var saveData = {
            //         Nodes: ths.nodeList,
            //         IsValidateOverride: true,
            //     }
            //     DataServices.SaveDisplayOrderNew2(saveData).then(function (response) {
            //         if(type == "TM"){
            //             if (Number(response.data.status) == 0) {
            //                 ths.ShowAlert(ths.$t('SuccessfullySaved', [ths.$t('BillingNodeConfiguration')]), "success", true, ths.$t("Alert"));
            //                 //   ths.GetNodeConfigurationData();
            //                  ths.$router.push({ name: 'BillingRule' });
            //             }
            //             else if(Number(response.data.status) == -2){
            //                 ths.confirmR(ths.$t("ErrorWhileValidateOverride"), true, (ths.$t("Alert")), function () {
            //                     var saveData = {
            //                         Nodes: ths.nodeList,
            //                         IsValidateOverride: false,
            //                     }
            //                     DataServices.SaveDisplayOrderNew2(saveData).then(function (response) { 
            //                         if (type == "TM") {
            //                             ths.ShowAlert(ths.$t('SuccessfullySaved', [ths.$t('BillingNodeConfiguration')]), "success", true, ths.$t("Alert"));
            //                             ths.$router.push({ name: 'BillingRule' });
            //                         }
            //                     });
            //                 });
            //             }
                         
            //         }
            //         else {
            //             vm.ShowAlert(response.data.msg || "Something went wrong!", "error", true, vm.$t("Alert"));
            //         }
            //     });
            // }
            // else{
                DataServices.SaveServiceRules(JSON.stringify(obj)).then(function (response) {
                    if (response && response.data != null && response.data.status == "Success") {
                        ths.ShowAlert(ths.$t('SuccessfullySaved', [ths.$t('BillingRuleConfiguration')]), "success", true, ths.$t("Alert"));
                        ths.GetNodeConfigurationData();
                    }
                })
            // }
          
        },
        CloseLimit() {
            this.EditLimitData = [];
            this.refCode = '';
            this.isAddLimit = false;
        },
        FetchData() {
            var vm = this;
            vm.isLoading = true;
            if (this.configurationId == null || this.configurationId == 0) {
                this.configurationId = 0;
            }
            var url = `configId=${vm.configurationId}&limitId=${vm.LimitId}&client_id=${this.clientId}&sort_by=${vm.Sort_By}sort_exp=${vm.Sort_Exp}&pagesize=${vm.PageSize}&pageNumber=${vm.PageNumber}`;
            return DataService.GetLimitListing(url).then((response) => {
                if (response.data != '') {
                    if (response.data.length > 0) {
                        vm.LimitData = response.data;
                        vm.LimitData = response.data.map(item => ({
                            ...item,
                            wrongDisplayOrder: (item.wrongDisplayOrder == null || item.wrongDisplayOrder == 0) ? 0 : 1
                        }));
                        vm.TotalRecords = vm.LimitData.length > 0 ? vm.LimitData[0].totalRecords : 0;
                        vm.noRecord = false;
                        if (this.mode === 'View') {
                            vm.listheaderbuttons[0].isvisible = false;
                            vm.listheaderbuttons[1].isvisible = false;
                            vm.isShowCheckBox =false;
                        }
                    }
                }
                else {
                    vm.LimitData = [];
                    vm.TotalRecords = 0;
                    vm.noRecord = true;
                }
                vm.isLoading = false;
            });
        },
        SetDisplayOrderBillingLimit: async function (type) {
            var vm = this;
            vm.isLoading = true;
            var obj = vm.LimitData;
            await DataService.SaveDisplayOrder(obj).then(async(response) => {
                if (response.data && response.data.msg == 'success') {
                    vm.FetchData();
                    await vm.$nextTick();
                    if(type!='MoveOrder'){
                    vm.ShowAlert(vm.$t('WrongLimitDisplayOrderMessage', [vm.$t('LimitValue')]), "success", true, vm.$t('Alert'));
                    }
                }
                vm.isLoading = false;
            });
        },
        UpOrder(row) {
            var vm = this;
            var currentIndex = vm.LimitData.findIndex(x => x.displayOrder === row.displayOrder);
            if (currentIndex > 0) {
                var prevItem = vm.LimitData.find(x => x.displayOrder === row.displayOrder - 1);
                if (prevItem) {
                    // Swap display orders
                    var tempOrder = row.displayOrder;
                    row.displayOrder = prevItem.displayOrder;
                    prevItem.displayOrder = tempOrder;
                    
                    // Call the API to save
                    vm.SetDisplayOrderBillingLimit('MoveOrder');
                }else{
                    vm.SetDisplayOrderBillingLimit('MoveOrder');
                }
            }
        },
        DownOrder(row) {
            var vm = this;
            var totalRecords = vm.LimitData.length;
            if (row.displayOrder < totalRecords) {
                var nextItem = vm.LimitData.find(x => x.displayOrder === row.displayOrder + 1);
                if (nextItem) {
                    // Swap display orders
                    var tempOrder = row.displayOrder;
                    row.displayOrder = nextItem.displayOrder;
                    nextItem.displayOrder = tempOrder;
                    
                    // Call the API to save
                    vm.SetDisplayOrderBillingLimit('MoveOrder');
                }else{
                    vm.SetDisplayOrderBillingLimit('MoveOrder');
                }
            }
        },
        isFirstItem(row) {
            // Get the minimum displayOrder value in the current data
            const minOrder = Math.min(...this.LimitData.map(item => item.displayOrder || 0));
            return row.displayOrder === minOrder;
        },
        isLastItem(row) {
            // Get the maximum displayOrder value in the current data
            const maxOrder = Math.max(...this.LimitData.map(item => item.displayOrder || 0));
            return row.displayOrder === maxOrder;
        },
        renderActions(row) {
            let rtnActionArray = [];
            this.listActions.forEach(actionItem => {
                let action = { ...actionItem };
                if (this.mode === 'View') {
                    action.isVisible = false;
                } else {
                    action.isVisible = true;
                }
                rtnActionArray.push(action);
            });
            return rtnActionArray;
        },
        actionButtonClick(callbackfunction, item, index, event, isChild) {
            switch (callbackfunction) {
                case 'EditRecord':
                    this.EditLimit(item);
                break;
            }
        },
        EditLimit(item) {
            var vm = this;
            var privilegeParams = `controller=BillingRule&action=EditBillingLimit`;
            DataService.CheckPrivilege(privilegeParams).then(function (response) {
            if (response.data) {
                vm.EditLimitData = item;
                vm.refCode = 'Update';
                vm.isAddLimit = true;
            }
            else {
                vm.ShowAlert(vm.$t('UnAuthorized'), "warning", vm.$t('Alert'));
                return false;
            }
            });
        },
      commonHeaderButtonClick(event) {
            switch (event.callbackfunction) {
                case "Add":
                    this.AddLimitRecord();
                    break;
                case "BackToList":
                    this.BackToList();
                    break;
                     case "Edit":
                     this.editConfiguration();
                    break;
                    case "Save":
                     this.SaveServiceRuless();
                    break;
                case "Delete":
                    this.commonDeleteData();
            }
        },
         SaveServiceRuless(){
            debugger
           this.$emit('save_configuration')
        },
        editConfiguration() {
            this.$emit('edit-configuration');
        },
        commonDeleteData: async function (event) {
            var vm = this;
            var val = "";

            $('.chkItems:checkbox:checked').not("[id^='chkAll_0']").each(function () {
                if (val.length > 0)
                    val += ',';
                val += $(this).val();
            });

            if (!val.length) {
                vm.ShowAlert(vm.$t("Selectanyrecordtodelete"), "failure", true, vm.$t("Alert"));
                return;
            }

            const privilegeParams = `controller=BillingRule&action=DeleteLimit`;
            const privilegeRes = await DataService.CheckPrivilege(privilegeParams);

            if (!privilegeRes.data) {
                vm.ShowAlert(vm.$t('UnAuthorized'), "warning", vm.$t('Alert'));
                return;
            }

            vm.confirmR(
                vm.$t("ConfirmDelete"),
                true,
                (vm.$t("Delete") + " " + vm.$t("LimitValue")),
                async function () {

                    const postJSON = {
                        limitIds: val,
                        statusId: 1003
                    };

                    const response = await DataService.DeleteBillingTemplateLimit(postJSON);
                    if (response.data.msg === 'success') {

                        $('.chkItems:checkbox:checked,#chkAll_0')
                            .prop("checked", false)
                            .removeAttr('checked');

                        $("#DeleteMultiple").addClass("disabled");

                        vm.ShowAlert(
                            vm.$t('DeletedSuccess', [vm.$t('LimitValue')]),
                            "success",
                            true,
                            vm.$t("Alert")
                        );

                        // ✅ Proper order execution
                        await vm.FetchData();
                        await vm.$nextTick();
                        await vm.SetDisplayOrderBillingLimit();
                    }
                    else {
                        vm.ShowAlert(
                            vm.$t('DeletedError', [vm.$t('LimitValue')]),
                            "failure",
                            true,
                            vm.$t("Alert")
                        );
                    }
                }
            );
        },
        BackToList() {
            var vm = this;
            vm.$router.push({name: vm.isBillingType ? 'BillingRule' : 'BillingRuleListing'});
        },
        AddLimitRecord() {
            var vm = this;
            var privilegeParams = `controller=BillingRule&action=AddBillingLimit`;
            DataService.CheckPrivilege(privilegeParams).then(function (response) {
            if (response.data) {
                vm.isAddLimit = true;
            }
            else {
                vm.ShowAlert(vm.$t('UnAuthorized'), "warning", vm.$t('Alert'));
                return false;
            }
            });
        },
        pagerMethod(value) {
            this.PageSize = value.PageSize;
            this.PageNumber = value.PageNumber;
            this.FetchData();
        },
        sortdata: function (SortBy) {
            this.SortBy = SortBy;
            var SortExp = 'ASC';
            if (this.SortExp == 'ASC') {
                SortExp = 'DESC';
            }
            this.SortExp = SortExp;
            this.SortBy = SortBy;
            this.SortExp = SortExp;
            this.PageNumber = 1;
            this.GroupStart = this.PageNumber;
            this.GroupEnd = this.PageNumber + 2;
            this.FetchData();
        },
        leftCommonSearch: async function (value) {
            this.PageNumber = value.PageNumber;
            this.isPaged = 1;
            if (value.searchCondition != "" && typeof value.searchCondition != 'undefined') {
                let str = value.searchConditionJson;
                const regex = /(WORK_CODE|WORK_CODE_CATEGORY_ID)\s*(?:LIKE\s+'?%?|=)\s*([^%')\s]+).*?/i;
                const m = str.match(regex);
                const column = m[1];
                const values = m[2];
                switch (column) {
                    case "WORK_CODE":
                        this.searchCondition = values;
                        break;
                    case "WORK_CODE_CATEGORY_ID":
                        this.categoryId = values;
                        break;
                }
            }
            else {
                this.categoryId = "";
                this.searchCondition = "";
            }
            this.FetchData();
        }
    },

}


</script>

